/* highlight.min.js (lightweight custom) */
document.querySelectorAll("pre code").forEach(block=>{
  let html=block.innerHTML;

  html=html
    .replace(/(\/\/.*)/g,'<span style="color:#6a9955;">$1</span>') // comments
    .replace(/(".*?"|'.*?')/g,'<span style="color:#ce9178;">$1</span>') // strings
    .replace(/\b(const|let|var|function|return|if|else|for|while|class|new)\b/g,
      '<span style="color:#569cd6;">$1</span>') // keywords
    .replace(/\b(true|false|null|undefined)\b/g,
      '<span style="color:#b5cea8;">$1</span>'); // literals

  block.innerHTML=html;
});
